<template>
  <div class="julian-portfolio">
    <v-layout row wrap mb-4>
      <v-flex xs12 text-xs-center>
        <v-btn @click="handleClick('all')" dark color="grey">all</v-btn>
        <v-btn @click="handleClick('design')" color="success">design</v-btn>
        <v-btn @click="handleClick('network')" dark color="cyan">network</v-btn>
        <v-btn @click="handleClick('system')" color="warning">system</v-btn>
        <v-btn @click="handleClick('full stack')" color="error">full stack</v-btn>
        <v-btn @click="handleClick('front end')" color="primary">front end</v-btn>
        <v-btn @click="handleClick('back end')" dark color="purple">back end</v-btn>
      </v-flex>
    </v-layout>
    <template v-if="list.length > 0">
      <template v-for="(portfolio, index) in list">
        <template v-if="index % 2 === 1">
          <Odd :odd="portfolio" :key="portfolio.id"/>   
        </template>
        <template v-else>
          <Even :even="portfolio" :key="portfolio.id"/>
        </template>
      </template>
    </template>
    <template v-else>
      <v-layout row wrap>
        <v-flex xs12 text-xs-center>
          <p class="red--text">No data to view ...</p>
        </v-flex>
      </v-layout>
    </template>
  </div>
</template>

<script>
  import { Odd, Even } from "@/components"
  import { portfolios } from "./data"

  export default {
    components: {
      Odd, Even
    },
    metaInfo: {
      titleTemplate: "%s | Portfolio"
    },
    data() {
      return {
        portfolios: portfolios,
        list: portfolios
      }
    },
    methods: {
      handleClick(keyword) {
        if (keyword !== 'all') {
          return this.list = this.portfolios.filter(portfolio => portfolio.category === keyword)
        } else {
          return this.list = this.portfolios
        }
      }
    }
  }
</script>
